#include <bits/stdc++.h>
using namespace std;
#define int long long
const int N = 2e5 + 5;
int n, m, len, tot;
int a[N], b[N], root[N];
int tree[N * 24], ls[N * 24], rs[N * 24];
void init() {
    vector<int> v(a + 1, a + 1 + n);
    sort(v.begin(), v.end());
    v.erase(unique(v.begin(), v.end()), v.end());
    len = v.size();
    for (int i = 1; i <= n; i++) {
        int p = lower_bound(v.begin(), v.end(), a[i]) - v.begin() + 1;
        b[p] = a[i];
        a[i] = p;
    }
}
void build(int &p, int l, int r) {
    p = ++tot; sz[p] = 0;
    if (l == r) return;
    int mid = (l + r) >> 1;
    build(ls[p], l, mid);
    build(rs[p], mid + 1, r);
}
void upd(int &p, int pre, int l, int r, int x) {
    p = ++tot;
    ls[p] = ls[pre]; rs[p] = rs[pre];
    tree[p] = tree[pre] + 1;
    if (l == r) return;
    int mid = (l + r) >> 1;
    if (x <= mid) upd(ls[p], ls[pre], l, mid, x);
    else upd(rs[p], rs[pre], mid + 1, r, x);
}
int qry(int u, int v, int l, int r, int k) {
    if (l == r) return l;
    int cnt = tree[ls[v]] - tree[ls[u]];
    int mid = (l + r) >> 1;
    if (k <= cnt) return qry(ls[u], ls[v], l, mid, k);
    return qry(rs[u], rs[v], mid + 1, r, k - cnt);
}
signed main() {
    ios::sync_with_stdio(0); cin.tie(0); cout.tie(0);
    cin >> n >> m;
    for (int i = 1; i <= n; i++) cin >> a[i];
    init();
    build(root[0], 1, len);
    for (int i = 1; i <= n; i++) upd(root[i], root[i - 1], 1, len, a[i]);
    while (m--) {
        int l, r, k;
        cin >> l >> r >> k;
        cout << b[qry(root[l - 1], root[r], 1, len, k)] << "\n";
    }
    return 0;
}
